var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"두 시간 뒤면 목적지에 도착할 걸세.","JPN":"２時間後には目的地に到着するだろう。","ENG":"We'll arrive at our destination in two hours.","TWN":"預計兩小時後到達目的地。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크리스 양도 물 한 잔하겠나?","JPN":"クリス君も水を飲むかい？","ENG":"Would you like a glass of water, Chris?","TWN":"克莉絲要不要也喝杯水？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 감사합니다.","JPN":"あ、ありがとうございます。","ENG":"Oh, thank you.","TWN":"啊，非常感謝。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서, 나에게 개인적으로 하고 싶다는 말이 뭐지?","JPN":"それで、私に個人的に話したいということは何だね。","ENG":"So, what is it that you wanted to talk to me in private about?","TWN":"所以你想和我單獨說什麼？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"흠 흠… 저, 그러니까.","JPN":"ゴホン、ゴホン……あの、えっと。","ENG":"Ahem... Well...","TWN":"咳咳……這個嘛。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"우선, 저희를 구해주셔서 감사드려요.","JPN":"まず、助けてくださりありがとうございました。","ENG":"First of all, thank you for saving us.","TWN":"首先，謝謝你救了我們。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그리고 염치없지만… 한 가지 묻고 싶은 게 있어서요.","JPN":"そして失礼ですが……一つ聞きたいことがあります。","ENG":"And although I might be stepping out of bounds... there's something I want to ask you.","TWN":"我有一件事想問……雖然很不要臉。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"실은 아까 침식체와 나누는 대화를 들었거든요. 데모고르곤에 관한 이야기.","JPN":"実は、さっき侵食体との会話を聞いていました。デモゴルゴンについての話。","ENG":"You see, I overheard your talk with the C.O. earlier. About the Demogorgon.","TWN":"我剛剛聽到了你和侵蝕體的對話，就是關於魔神的話。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"귀가 밝은 친구로군.","JPN":"耳がとても良いみたいだね。","ENG":"Don't you have keen ears.","TWN":"耳朵可真靈。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"죄송해요.","JPN":"ごめんなさい。","ENG":"I'm sorry.","TWN":"對不起。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"처음엔 우연히 마주쳐서 도움을 받았다고 생각했지만… 당신이 레아 씨의 정체를 얘기하는 걸 듣고도 어떻게 모른 척할 수 있겠어요?","JPN":"最初は偶然出会い、助けてもらったと思っていましたけど...…あなたがレアさんの正体について話していることを聞いたら、知らないふりはできませんでした。","ENG":"I thought it was just a coincidence that you helped us at first, but... I couldn't act dumb after hearing you talk about Leah's identity.","TWN":"一開始只是以為偶然遇到你並得到了幫助……但聽到你提及蕾亞的真實身分後，我實在按耐不住好奇心。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"가장 먼저, 우리의 만남은 우연이 맞다네.","JPN":"まず、私たちの出会いは偶然であっている。","ENG":"Firstly, our encounter is purely coincidental.","TWN":"首先，我們會遇到確實是偶然。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 레아 양에 관한 정보라면 얼마 전 세간을 떠들썩하게 했던 타나베린 사건에 대해 내 부하가 전해준 보고서를 읽었거든.","JPN":"そして、レア君に関する情報ならこの前騒ぎになったタナベリン事件に関する報告書を読んだからだ。","ENG":"Also, I know about Leah because I read the report my employee gave me about the Tanaberin incident that was recently in the news.","TWN":"至於蕾亞的情報，是從我的員工給我的一份報告書上看到的。是關於之前轟動一時的達那貝林事件的報告書。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"류드밀라를 통해 자네에게 맡긴 얼터니움이 다행히 제 역할을 해준 것 같더군.","JPN":"リュドミラを通じて君たちに預けたオルタニウムがちゃんと役割を果たしたようだね。","ENG":"Fortunately, the Alternium I left you through Lyudmila did its job.","TWN":"看來，我請盧德米拉轉交給你的黑化永恆之金發揮了作用。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네…?","JPN":"えっ……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아앗!","JPN":"ああっ！","ENG":"Oh!","TWN":"啊啊！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그럼 당신이 류드밀라 씨가 주셨던 그 보석의 주인인 건가요?!","JPN":"それじゃ、あなたがリュドミラさんが渡した宝石の持ち主なんですか！？","ENG":"Then you're the owner of the gem that Lyudmila gave me?!","TWN":"你就是盧德米拉給我的那顆寶石的主人？！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"주인이란 표현은 어울리지 않아.","JPN":"持ち主という表現はふさわしくないな。","ENG":"\\"Owner\\" isn't how I would put it.","TWN":"主人這個表達不太準確。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 보석은 가진다고 해서 사용할 수 있는 물건이 아니니 말일세.","JPN":"その宝石は持っているからといって思い通りに使えるわけではないから。","ENG":"That gem is not something you can use just because you are in possession of it.","TWN":"因為那個寶石並不是只要擁有就能使用的東西。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하하… 아무튼 다행이네요.","JPN":"はは……とにかくよかったです。","ENG":"Ha ha... I'm glad to meet you anyway.","TWN":"哈哈……總之我放心了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"쫓기듯이 타나베린을 떠난 뒤로, 늘 마음에 걸렸어요.","JPN":"追われるようにタナベリンを出てから、ずっと気がかりでした。","ENG":"Ever since I left Tanaberin in a hurry, it's always been bugging me.","TWN":"自從倉皇逃離達那貝林之後，我就一直惦記著這件事。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"고마운 분들이 너무 많은데… 떠날 때 제대로 감사도 드리지 못했거든요.","JPN":"お世話になった人たちがたくさんいたのに……ちゃんとしたお礼も言えず出てきてしまったんです。","ENG":"There are so many people I'm grateful for... But I couldn't even thank them before I left.","TWN":"我有很多要感謝的人……卻在離開時沒能好好道謝。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"굳이 말하지 않아도 그들은 자네들의 사정을 이해할 걸세. 나도 마찬가지고.","JPN":"きっと彼らは君たちの事情を理解しているだろう。もちろん私もそうだ。","ENG":"I'm sure they'll understand, even if you don't say it out loud. The same is true for me too.","TWN":"你不必說出來，他們會理解的。我也一樣。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그래도, 언젠가 보석을 돌려 드려야겠다는 생각은 하고 있었어요.","JPN":"でも、いつかは宝石を返さなければならないと思っていました。","ENG":"But still, I was thinking that I should return the gem to its owner one day.","TWN":"儘管如此，我也一直在想一定要把寶石還給主人。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"관리국에 그 보석이 깃든 장비를 맡겨 둔 것도…","JPN":"管理局にその宝石をはめ込んだ装備を預けたことも……","ENG":"The reason why I left the gem-infused gear with the Administration is...","TWN":"將蘊含那顆寶石的裝備交給管理局……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"제가 그런 엄청난 물건을 가지고 있다는 사실이 부담됐거든요.","JPN":"私があんな凄いものを持っているという事実が負担に思えたからです。","ENG":"because I felt weighed down just knowing that something as incredible as that was in my possession.","TWN":"以及自己拿著如此重要的東西這一事實讓我非常感到負擔。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미안하지만, 자넨 그걸 나에게 돌려줄 수 없네.","JPN":"すまないが、君はそれを私に返すことはできない。","ENG":"I'm sorry, but you cannot give that back to me.","TWN":"不好意思，你還不能把它還給我。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네…? 어째서죠?","JPN":"はい……？　どうしてですか？","ENG":"Huh...? Why not?","TWN":"什麼……？為什麼？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"얼터니움은 자네의 바람이 완전히 이루어지기 전까지 본래 형태로 돌아오지 않을 테니까.","JPN":"オルタニウムは君の願いが完全に叶うまで、本来の姿には戻らないからね。","ENG":"Until your wish comes true, Alternium will not return to its original form.","TWN":"在您的願望完全實現之前，黑化永恆之金不會恢復原樣。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그럴 리가요. 전 타나베린에서의 목적은 달성했는데요?","JPN":"そんなはずは。私はタナベリンでの目的を達成しましたよ？","ENG":"That can't be true. But I achieved my goal in Tanaberin.","TWN":"怎麼會呢，我在達那貝林的目的已經達成了呀？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"전 제 힘만으론 할 수 없는 일을 그것 덕분에 이뤄냈는데…","JPN":"私は自分の力だけではできないことをその宝石のおかげで達成したのに……","ENG":"It helped me achieve something I wouldn't have been able to without it...","TWN":"我在它的幫助下完成了獨自一人無法完成的事情……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그저 한 고비를 넘겼을 뿐, 아직 아무것도 끝난 게 아니잖나?","JPN":"それは山を一つ乗り越えただけで、まだ全てが終わったわけではないのだろう？","ENG":"That's just one hurdle. Nothing has reached a conclusion, has it?","TWN":"你只是度過了一次危機，一切並沒有完全結束不是嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그러네요.","JPN":"そうですね。","ENG":"You're right.","TWN":"確實。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그로니아 정부는 물론이고, 그런 괴물들에게 쫓길 정도로… 레아 씨는 아직 과거의 일들을 짊어지고 있으니까요.","JPN":"グロニア政府はもちろん、あんな化け物に追われるほど……レアさんはまだ過去のことを背負っていますから。","ENG":"Gronia's government, and now this monster... The reason Leah is being chased by them is because she's still bearing the burden of the past.","TWN":"蕾亞依然肩負著過去的那些事……比如被格羅尼亞政府和那些怪物追殺……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"앞으로의 일들은 지옥의 문턱에서 악마를 끌어내는 것보다 훨씬 힘겨울 걸세.","JPN":"これからのことは地獄の扉から悪魔を引きずりだすより、はるかに厳しいだろう。","ENG":"The road ahead will be much harder than dragging a demon out from the threshold of hell.","TWN":"以後你會遇到比把怪物打入地獄還要艱難的事情。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"각오는 하고 있어요. 단지…","JPN":"覚悟はしています。ただ……","ENG":"I'm prepared to do whatever it takes. But...","TWN":"我做好覺悟了。只是……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"실낱 같은 희망에서 건져낸 이 모든 게 언젠가 물거품처럼 사라질까 두려울 뿐이예요.","JPN":"一筋の希望から救い出したこのことがすべて、いつか泡のように消えるのではないかと思うと怖いだけです。","ENG":"I'm just afraid that this sliver of hope will someday just disappear into thin air.","TWN":"我只是擔心這一絲希望之光照亮的所有東西最終都會化為烏有。"},"stage":{"bg":"HARMONY2_07","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"영원히 행복하게 잘 살았습니다- 처럼 이상적인 결말은 누구나 좋아하지.","JPN":"永遠に幸せに暮らしました-という理想的な結末は誰もが好むものだ。","ENG":"Everyone loves a \\"happily-ever-after\\" ending.","TWN":"每個人都喜歡幸福圓滿的結局。"},"stage":{"bg":"HARMONY2_07","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 이루지 못할 결말을 얻기 위해 평생을 불행 속에 갇혀 살아야 한다면…","JPN":"だが、叶えることができない結末のを手に入れるために一生不幸に生きていくなら……","ENG":"But living in misery for the rest of your life in hopes of achieving an unreachable ending...","TWN":"但是如果為了一個不可能實現的結局而不得不在痛苦中度過餘生……"},"stage":{"bg":"HARMONY2_07","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그건 이면세계에 갇힌 그림자의 사념과 다를 바가 없지 않겠나?","JPN":"それは裏世界に閉じ込められたシャドウの思念となんら変わらないのではないのか？","ENG":"How is that any different than a Shadow's will trapped in the Counterside?","TWN":"豈不是和困在異界的暗影沒兩樣嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"아, 중사.","JPN":"あ、軍曹。","ENG":"Oh, Sergeant.","TWN":"啊，中士。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"얘기는 잘 끝났어?","JPN":"話は終わった？","ENG":"How was your talk? Good?","TWN":"談完了嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…네.","JPN":"……はい。","ENG":"...Yes.","TWN":"……是的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레아 씨. 저 생각해봤는데요.","JPN":"レアさん。私、考えたんですが。","ENG":"Leah, I've been thinking.","TWN":"蕾亞，我一直在想一件事。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"제가 레아 씨에게 도움을 줬다고 해서, 레아 씨가 제 바람에 얽매이지 않았으면 좋겠어요.","JPN":"私がレアさんを助けたという理由で、レアさんが私の願望に縛られるのを私は望んでいません。","ENG":"I hope you're not bound to my wishes just because I helped you.","TWN":"我雖然幫助過你，但我不想你被我牽連。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"갑자기 그게 무슨 소리야?","JPN":"いきなりなに言ってるんだ？","ENG":"What are you talking about?","TWN":"你突然說什麼？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이 수송선에 타기로 한 거… 단지 도시가 위험하기 때문만은 아니잖아요.","JPN":"この輸送船に乗ると決めたのは……ただ、都市が危ないからではないでしょう？","ENG":"The reason you got on this transport aircraft... It's not just because the city is in danger, right?","TWN":"你選擇乘坐這艘飛船……不僅僅是因為這座城市很危險。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레아 씨가 매일 밤 네퀴티아의 기억 때문에 악몽을 꾸고 있다는 거 알아요.","JPN":"レアさんがネキティアの記憶のせいで毎晩のように悪夢を見ているのは知っています。","ENG":"I know that you have nightmares almost every night because of Nequitia's memories.","TWN":"我知道蕾亞每晚都會因為莉奎蒂亞的記憶而受到惡夢的折磨。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하지만 난 너와 약속했잖아. 공정한 재판을 받고, 죗값을 치르겠다고.","JPN":"でも、私は君と約束したよね。公正な裁判を受け、罪を償うと。","ENG":"But you and I made a promise. To get a fair trial and pay for my crimes.","TWN":"但我答應過你，我會接受公正的審判並為我的罪行付出代價。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"재판을 받은 뒤에도 평생을 똑같은 악몽에 시달릴 뿐이겠죠.","JPN":"裁判を受けた後も一生同じ悪夢にうなされるだけです。","ENG":"But even if you get your trial, you'll still be struggling with the same nightmares for the rest of your life.","TWN":"即使審判結束後，你仍然會遭受惡夢的折磨一輩子。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저는요. 레아 씨에게 무슨 성녀 같은 고고한 희생을 바라고 끌어낸 거 아니에요.","JPN":"私は。レアさんに聖女のような気高い犠牲を望んで連れ出したわけじゃないんです。","ENG":"You know, I didn't pull you out so you could sacrifice yourself like a saint.","TWN":"我把你救出來並不是希望你做出聖女一般高尚的犧牲。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"애초에 당신은 그런 사람도 아니었으니까요.","JPN":"そもそもあなたはそんな人じゃなかったから。","ENG":"I mean, you're not even the type of person to do so in the first place.","TWN":"你本來就不是那樣的人。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하하… 신랄한 지적이네.","JPN":"はは……辛辣だね。","ENG":"Haha... That was rather direct.","TWN":"哈哈……說得好直接。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그러니까 무슨 생각을 하고 있건, 목숨 하나로 속죄를 끝낼 생각은 하지 마요.","JPN":"だから何を考えているかわからないけど、自分の命で罪滅ぼしをしようだなんて思わないでほしいです。","ENG":"So whatever you're thinking of doing, don't try to repent by taking your own life.","TWN":"所以無論你在想什麼，都不要試圖用自己的一條命來贖你的罪。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"평생 죄를 짊어지고 고뇌하더라도, 어떻게든 살아남으라고요. 레버넌트가 그랬던 것처럼.","JPN":"一生罪を背負って苦悩してでも、なんとか生き延びてください。レヴナントがそうしたように。","ENG":"Even if you bear the weight of the sin for the rest of your life, you have to live. Just like Revenant did.","TWN":"即使罪惡感會折磨你一輩子，你也要堅持活下去，就像亡靈一樣。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그럼, 저도 당신이 어떤 선택을 하든 존중할 테니까.","JPN":"それなら、私もあなたがどんな選択をしようとも尊重します。","ENG":"Then, I'll respect any decision you make in return.","TWN":"這樣的話，我也會尊重你的任何選擇。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"…중사.","JPN":"……軍曹。","ENG":"...Sergeant.","TWN":"……中士。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"쿠울…","JPN":"ぐうぅぅ……","ENG":"Zzz...","TWN":"呼嚕……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"드르렁…","JPN":"ぐう……","ENG":"*Snore...*","TWN":"呼嚕……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…푸아-","JPN":"……すや-","ENG":"...*Snore.*","TWN":"……噗——"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다들 깊이 잠들었군. 그렇게 고생을 했으니 많이 피곤했겠지.","JPN":"みんなぐっすり寝ているね。あんなに大変だったんだ、疲れていて当然か。","ENG":"They're all fast asleep. They must be exhausted after going through all that trouble.","TWN":"大家都睡得很死，也難怪，白天受了那麼多罪。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…아, 사장님.","JPN":"……あ、社長。","ENG":"...Oh, Boss.","TWN":"……啊，老闆。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미나 양은 쉬어두지 않아도 괜찮겠나?","JPN":"ミナ君は休まなくてもいいのか？","ENG":"Shouldn't you also be resting, Mina?","TWN":"米娜不需要休息一下嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"응, 하늘 구경이나 할까 했는데 아까부터 계속 눈보라만 보이네.","JPN":"うん、空を見ようと思ったんだけど、さっきからずっと吹雪しか見えないんだ。","ENG":"Yeah. I was thinking of gazing at the sky, but all I see are snowstorms.","TWN":"嗯。我本來想看看天空，但只看到了暴風雪。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"사건의 중심에 다가갈수록 악천후는 점점 더 심해질 걸세.","JPN":"事件の重心に近づくほど悪天候はさらに酷くなるだろう。","ENG":"The weather will get worse as we head toward the center of the incident.","TWN":"越靠近事件的中心，天氣會變得越來越惡劣。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이게 맞는 방향이라는 뜻이지.","JPN":"つまり正しい方向ということだ。","ENG":"This just means that we're headed in the right direction.","TWN":"這說明我們的方向是正確的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사장님은… 녀석이 하는 말을 이해했어?","JPN":"社長は……あいつの言葉、理解した？","ENG":"Boss... did you understand what that thing was saying?","TWN":"老闆……你能聽懂那傢伙說的話嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"눈이 그치지 않는 무덤이라니. 난 그게 아직도 무슨 뜻인지 모르겠는데.","JPN":"雪が止まない墓って。私はまだ意味がわからないんだけど。","ENG":"Grave of endless snow? I still don't get what that means.","TWN":"雪不會停的墳墓，不知道到底是什麼意思。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"눈이 그치지 않는 현상을 가진 고심도 좌표는 그림자전당 하나뿐일세.","JPN":"雪が止まない現象がある高深度の座標は影の殿堂、ただ一つだけだ。","ENG":"There's only one hyperdepth coordinate that has the phenomenon of endless snow. It's the Shadow Palace.","TWN":"不停下雪的高深度座標只有暗影殿堂一處。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 그녀의 마지막 행적인 로터스엔 그림자전당으로 통하는 대균열이 있지.","JPN":"そして彼女の最後の行跡であるロータスには影の殿堂へと繋がった大亀裂がある。","ENG":"And in Lotus, which is where the last traces of her are, there is a Grand Dimension Crevice connected to the Shadow Palace.","TWN":"並且她留下最後行蹤的洛德斯也有通往暗影殿堂的大峽谷。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그렇다면 녀석이 말한 무덤이란 건 역시…","JPN":"だったら、あいつが言った墓とはやっぱり……","ENG":"Then by grave, he meant...","TWN":"這麼說，他所說的墳墓果然是……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"마왕 네헤모트의 힘을 봉인하고 있던 그 함선과 비슷한 거겠지?","JPN":"魔王ネヘモトの力を封印していたあの艦船と似たようなものなのか？","ENG":"something similar to the ship that was sealing Demon Lord Nehemoth's powers?","TWN":"應該和封印著魔王貝赫莫特的那艘艦船差不多吧？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 스완은 그 관의 봉인을 열고 싶어하더군.","JPN":"そうだ。スワンはその棺の封印を解きたいのだ。","ENG":"Correct, and Swan seems to want to open the sealed coffin.","TWN":"是的。史旺想打破那個棺材的封印。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"기상조절 시스템을 뚫고 이렇게 눈이 쏟아질 정도라면, 지금쯤 샤레이드를 비롯한 전세계가 눈이 오고 있을 걸세.","JPN":"気象調整システムを突破してこんなに雪が降るなら、今ごろシャレードを含む世界中に雪が降っているだろう。","ENG":"Given the amount of snow falling through the Weather Control System, it should be snowing all over the world, including Charade.","TWN":"這裡的雪竟然可以打破氣象調節系統的調節，那麼包括查雷德在內的世界各地一定都在下雪。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"독을 한가득 품은 관의 틈이 열렸으니, 그 독기가 현실 곳곳으로 퍼진 셈이지.","JPN":"毒に満ちている棺に隙間ができ、その毒が現実のあちこちに広がったわけだ。","ENG":"The coffin filled with poison cracked, and the posion will now spread all throughout the Normalside.","TWN":"充滿劇毒的棺材被打開了一條縫隙，所以裡面的毒氣散發到現實世界各地了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 봉인이 아직 완전히 열리진 않았어.","JPN":"しかし、まだ封印が完全に解かれたわけではない。","ENG":"Luckily, the coffin isn't fully open yet.","TWN":"但好在封印尚未完全打開。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우리에게도 아직 기회는 있다네.","JPN":"こちらにもまだチャンスはあるのだ。","ENG":"Which means we still have a chance.","TWN":"我們還有機會。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"우리가 그걸 막지 못하면 마왕이 깨어나는 건가?","JPN":"私たちがそれを食い止めないと魔王が目覚めるのか？","ENG":"If we can't stop it, will the Demon Lord awaken?","TWN":"如果我們不阻止它，魔鬼會醒來嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 되겠지.","JPN":"そうなるな。","ENG":"I believe so.","TWN":"應該是吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"스완이 노리는 그 그림자 전당의 관 속에는… 대체 어떤 녀석이 있는 거야?","JPN":"スワンが狙っている影の殿堂にある棺の中には……一体どんなやつがいるんだ？","ENG":"Who's... inside the coffin in the Shadow Palace that Swan is after?","TWN":"史旺尋找的那個暗影殿堂的棺材裡面……究竟躺著什麼人？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"타기리온.","JPN":"タギリオン。","ENG":"Thagirion.","TWN":"塔基里翁。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"온전한 힘을 가진 그녀가 현실로 부상한다면… 세계는 붕괴하고 말 거예요.","JPN":"完全な状態の彼女が現実に出てきたら……世界は滅んでしまいます。","ENG":"If she emerges in the Normalside with all her powers... the world will collapse.","TWN":"如果恢復所有力量的她降臨現世……世界會徹底崩塌。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그녀는 온 현실을 그림자로 만들고 싶어 할 테니까요.","JPN":"彼女は現実の全てをシャドウにすることを望むだろうから。","ENG":"Because she will want to corrupt the Normalside and drown it in shadows.","TWN":"她會讓整個現世變成暗影。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"당신이 그걸 어떻게 알아?","JPN":"なんでそれを知っているんだ？","ENG":"How do you know that?","TWN":"你怎麼知道？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"제 옛 이름은 네퀴티아.","JPN":"私の昔の名前はネキティア。","ENG":"My former name is Nequitia.","TWN":"我以前的名字叫莉奎蒂亞。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"마왕 타기리온에 의해 무너진 세계, 엘리시온의 마지막 생존자이자…","JPN":"魔王タギリオンによって滅んだ世界、エリシオンの最後の生き残りで……","ENG":"The last survivor of Elysion, the world that Demon Lord Thagirion destroyed...","TWN":"是被魔王塔基里翁毀滅的艾利森世界中唯一的倖存者……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"…그녀를 탄생시킨 죄인입니다.","JPN":"……彼女を誕生させてしまった罪人です。","ENG":"...And the sinner who created her.","TWN":"……也是使她誕生出來的罪人。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};